// ── DİL ──────────────────────────────────────────────────────────
let currentLang = localStorage.getItem('bd_lang') || 'tr';
function setLang(l) {
  currentLang = l;
  localStorage.setItem('bd_lang', l);
  document.querySelectorAll('.lang-btn').forEach(b => b.classList.toggle('active', b.dataset.lang === l));
  document.documentElement.lang = l;
}

